Notification.ShortMessage:
{SR('Список модулей с истекающим сроком лицензии:')}
{TableStart()} {for item in {$New.ExpiringComponents}}
- {$item.Title}: {SR('Лицензия истекает')} - {DateTimeFormat(ExpirationDate({$item}); 'dd.MM.yyyy')} ({if ComponentLicenseIsExpired({$item})}{SR('Лицензия истекла')}{else}{SR('Осталось дней:')} {DaysBeforeExpiration({$item})}{end if}){end}
{TableEnd()}

{SR('Информация об установленных модулях ELMA представлена на странице:')} {Link(SR('Компоненты'); '{#BaseUrl#}' + '/Common/License')}

